"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[78391],{41747(e,a,t){t.r(a),t.d(a,{assets:()=>l,contentTitle:()=>o,default:()=>h,frontMatter:()=>r,metadata:()=>i,toc:()=>c});const i=JSON.parse('{"id":"UserGuide/C48_ML_Datasets/S03_Data_collection_and_identification","title":"Data collection and identification","description":"The data (images or features) in your datasets must properly represent what you are trying to classify. The quality and quantity of your data directly impacts the classifier\'s training. To help ensure proper data, collect it using the final imaging setup (the same camera, lens, and illumination) and use real samples (images) of the subject matter, or as close as possible to them.","source":"@site/docs/UserGuide/C48_ML_Datasets/S03_Data_collection_and_identification.md","sourceDirName":"UserGuide/C48_ML_Datasets","slug":"/UserGuide/C48_ML_Datasets/S03_Data_collection_and_identification","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C48_ML_Datasets/S03_Data_collection_and_identification","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"Machine learning fundamentals","chapter":"ML_Datasets","section":"Data_collection_and_identification","module_tag":"class","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / Machine learning fundamentals / Datasets / Data collection and identification"},"sidebar":"userGuideSidebar","previous":{"title":"Basic concepts for datasets","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C48_ML_Datasets/S02_Basic_concepts"},"next":{"title":"Different datasets and how they are split","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C48_ML_Datasets/S04_Different_datasets_and_how_they_are_split"}}');var s=t(74848),n=t(28453);const r={doctype:"UserGuide",part:"Machine learning fundamentals",chapter:"ML_Datasets",section:"Data_collection_and_identification",module_tag:"class",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / Machine learning fundamentals / Datasets / Data collection and identification"},o="Data collection and identification",l={},c=[{value:"Data foresight",id:"data-foresight",level:2},{value:"Classes and labeling (the ground truth)",id:"classes-and-labeling-the-ground-truth",level:2},{value:"UUID",id:"uuid",level:2},{value:"AIL_UUID utility macros for C users",id:"ail_uuid-utility-macros-for-c-users",level:3}];function d(e){const a={a:"a",blockquote:"blockquote",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,n.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(a.header,{children:(0,s.jsx)(a.h1,{id:"data-collection-and-identification",children:"Data collection and identification"})}),"\n",(0,s.jsx)(a.p,{children:"The data (images or features) in your datasets must properly represent what you are trying to classify. The quality and quantity of your data directly impacts the classifier's training. To help ensure proper data, collect it using the final imaging setup (the same camera, lens, and illumination) and use real samples (images) of the subject matter, or as close as possible to them."}),"\n",(0,s.jsx)(a.p,{children:"Your dataset should include all expected variations of what you want to classify, and in sufficient number, such as variations in aspect, color, intensity, rotation, and dimension. Pay special attention to variations that are difficult to obtain and, if necessary, use augmentation to synthesize such variations (for example, rotation and flip). The following example illustrates variations (images) of a single apple object (class)."}),"\n",(0,s.jsx)(a.p,{children:(0,s.jsx)(a.em,{children:"[Image: MclassClassesAllVariations.png]"})}),"\n",(0,s.jsx)(a.p,{children:"To classify multiple objects, each of which is a separate class (for example, apples, oranges, and pears), you must provide, for each class, numerous training images of every variation. Aurora Imaging Library internally divides that data, which usually occupies a lot of memory, into several sets (for example, by using mini-batches or bagging). Gathering as much data as possible helps ensure it is evenly consumed by training."}),"\n",(0,s.jsx)(a.p,{children:"It is recommended to have a minimum of 500 dataset entries (images or sets of features) per class, although simple applications can require less, and complex applications can require more. The number of entries required to properly train a classifier context depends on the complexity of the problem, the number of classes, and the number of variations within the classes. Typically, the data in all your datasets come from the same distribution (the same environment and setup)."}),"\n",(0,s.jsxs)(a.p,{children:["A balanced dataset is key to achieving a properly trained classifier. In a balanced dataset, each class should have the same number of entries representing it and, within each class, you should have the same number of entries representing each variation. You can obtain a balanced dataset by performing data augmentation with ",(0,s.jsx)(a.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/class/MclassPrepareData",children:(0,s.jsx)(a.code,{children:"MclassPrepareData"})}),". Obtaining a perfectly balanced dataset for segmentation or object detection is not always possible because an image might contain multiple regions with different labels."]}),"\n",(0,s.jsxs)(a.blockquote,{children:["\n",(0,s.jsxs)(a.p,{children:[(0,s.jsx)(a.strong,{children:"Note:"})," These dataset recommendations are for a complete (default) training, which means you are training a classifier from the ground up; other types of training, such as transfer learning, require less data. For more information, see ",(0,s.jsx)(a.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C49_ML_Training/S03_Fundamental_decisions_and_settings",children:"Training modes"}),"."]}),"\n"]}),"\n",(0,s.jsx)(a.h2,{id:"data-foresight",children:"Data foresight"}),"\n",(0,s.jsx)(a.p,{children:"The data that you collect and the classes with which it is organized must represent, as much as possible, a well-posed and consistent problem that you want to train the classifier to solve. Be aware that there are usually several ways to formulate a problem and present the data to solve that problem; it is imperative that this is done in a consistent and perceptive manner. You must know the problem that you want to solve and provide the data to solve it, while at the same time being mindful of ambiguities or unwanted associations that could lead to uncertain or even mistaken classifications."}),"\n",(0,s.jsx)(a.p,{children:"Illumination variances in your data represents one of the ways a classifier can make inadvertent associations. If illumination is irrelevant to determining the class, the data with which you train should contain different illuminations to remove the bias that a specific illumination condition can introduce."}),"\n",(0,s.jsx)(a.p,{children:"For example, if your dataset has images of good parts taken near a window on a cloudy day and images of defective parts taken near that window on a sunny day, it is likely for the classifier to learn that a dark image means a good part and a bright image means a defective part. It is vital to anticipate the important variations and provide that data; this allows the classifier to properly learn how to solve the problem without unwanted bias."}),"\n",(0,s.jsx)(a.h2,{id:"classes-and-labeling-the-ground-truth",children:"Classes and labeling (the ground truth)"}),"\n",(0,s.jsx)(a.p,{children:"The Classification module uses supervised training, which requires you to label your dataset entries with the class they represent. This label is called the ground truth (GT). Class labels must be unique. Datasets often have two or more class labels, although this depends on the problem you are solving. Object detection, for example, requires at least one class, and anomaly detection requires no explicit classes (although implicitly one is inferred)."}),"\n",(0,s.jsx)(a.p,{children:"Although anomaly detection does not require labeling, it can be considered an implied two-class prediction problem. By default, all dataset entries are considered non-anomalous (which can infer a type of ground truth label that identifies the image as non-anomalous). Once these images are learned at training time, the classifier can then implicitly predict two classes of images; that is, the non-anomalous ones, and the anomalous ones/everything else."}),"\n",(0,s.jsxs)(a.p,{children:["For an explicit two-class problem, which applies to other machine learning tasks, you could specify one of two class labels for every dataset entry; that is, every image (or image region), or every set of features in a dataset, is identified as one of these two classes. This can in some cases prove more practical than anomaly detection; for example, if you have a more significant number bad images, it might make sense for the classifier to explicitly learn them, along with the good images. In such cases, your two class labels could be generally defined as ",(0,s.jsx)(a.em,{children:"Good"})," and ",(0,s.jsx)(a.em,{children:"Bad"}),"."]}),"\n",(0,s.jsxs)(a.p,{children:["For an ",(0,s.jsx)(a.em,{children:"n"}),"-class problem, you could specify one of ",(0,s.jsx)(a.em,{children:"n"}),"-labels (for example, ",(0,s.jsx)(a.em,{children:"ClassMetal"}),", ",(0,s.jsx)(a.em,{children:"ClassCarpet"}),", or ",(0,s.jsx)(a.em,{children:"ClassWood"}),") for every dataset entry (every image or set of features in a dataset is identified as one of these ",(0,s.jsx)(a.em,{children:"n"}),"-classes). Another set of labels to use for such problems is ",(0,s.jsx)(a.em,{children:"ClassMetalGood"}),", ",(0,s.jsx)(a.em,{children:"ClassMetalWithHole"}),", or ",(0,s.jsx)(a.em,{children:"ClassMetalWithScratch"}),". Note, for image datasets, you often have one label (class) per image region (therefore, you can have multiple labels and classes for each image) rather than one label per image (which is generally for image classification)."]}),"\n",(0,s.jsx)(a.p,{children:"To label whole images and image regions (that is, identify the class they represent), you can use Aurora Imaging CoPilot. Alternatively, you can build a simple utility that calls Aurora Imaging Library."}),"\n",(0,s.jsxs)(a.p,{children:["If you have a large amount of data to label, it might be possible to label some of it, train your classifier context, call the prediction operation to label the unlabeled dataset entries, and then use those newly labeled entries in your training dataset to continue the training process. For more information, see ",(0,s.jsx)(a.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C50_ML_Prediction/S04_Advanced_techniques",children:"Assisted labeling"}),"."]}),"\n",(0,s.jsx)(a.p,{children:"Another option for managing data labeling is using anomaly detection as a preliminary step for other machine learning tasks. For example, if you ultimately want to identify a variety of different defects in an image, you can use anomaly detection to find all defective (anomalous) images first. This lets you know which images should be sent for manual labeling so the specific defective class description can be assigned (that is, the specific type of anomaly), and which images do not need any manual labeling since you have already determined they are defect free (non-anomalous). Reliably reducing the amount of image data that requires manual labeling can often cut costs and development time significantly."}),"\n",(0,s.jsx)(a.h2,{id:"uuid",children:"UUID"}),"\n",(0,s.jsx)(a.p,{children:"A UUID refers to a universally unique identifier that is used for identification purposes across unrelated systems and applications. The following is an example of an automatically generated key (UUID): 87fbb05a-b078-4389-8ad2-2a2f9707c8f4."}),"\n",(0,s.jsx)(a.p,{children:"Every dataset entry has a UUID value that uniquely identifies it; this is also known as the entry's key. Since datasets can contain numerous entries from multiple datasets constructed on unrelated systems, this universally unique key helps ensure that the entries from all the datasets are not confused with each other."}),"\n",(0,s.jsxs)(a.p,{children:["Aurora Imaging Library automatically generates a UUID when required, such as, when you add an entry to a dataset (",(0,s.jsx)(a.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/class/MclassControl",children:(0,s.jsx)(a.code,{children:"M_ENTRY_ADD"})}),"). Although you do not create you own UUIDs, you can use them to access an entry to, for example, inquire about it or modify it."]}),"\n",(0,s.jsxs)(a.p,{children:["The Aurora Imaging Library custom data type for UUIDs is ",(0,s.jsx)(a.em,{children:"AIL_UUID"}),". When using an ",(0,s.jsx)(a.em,{children:"AIL_UUID"})," variable, Aurora Imaging Library defines the ",(0,s.jsx)(a.strong,{children:"M_DEFAULT_UUID"})," and ",(0,s.jsx)(a.strong,{children:"M_NULL_UUID"})," constants, which allow you to specify the corresponding default UUID value or a null UUID value."]}),"\n",(0,s.jsx)(a.h3,{id:"ail_uuid-utility-macros-for-c-users",children:"AIL_UUID utility macros for C users"}),"\n",(0,s.jsxs)(a.p,{children:["To perform comparisons with ",(0,s.jsx)(a.em,{children:"AIL_UUID"})," values in C, use the following macros:"]}),"\n",(0,s.jsxs)(a.ul,{children:["\n",(0,s.jsxs)(a.li,{children:[(0,s.jsx)(a.strong,{children:"M_COMPARE_AIL_UUID(VarA, VarB)"}),".\r\nThis macro evaluates an equal (==) comparison operation between two variables."]}),"\n",(0,s.jsxs)(a.li,{children:[(0,s.jsx)(a.strong,{children:"M_IS_DEFAULT_UUID(VarA)"})," or ",(0,s.jsx)(a.strong,{children:"M_IS_DEFAULT_KEY(VarA)"}),".\r\nThese macros evaluate whether a variable is equal to the default UUID. These macros are equivalent."]}),"\n",(0,s.jsxs)(a.li,{children:[(0,s.jsx)(a.strong,{children:"M_IS_NULL_UUID(VarB)"})," or ",(0,s.jsx)(a.strong,{children:"M_IS_NULL_KEY(VarB)"}),".\r\nThese macros evaluate whether a variable is equal to a null UUID. These macros are equivalent."]}),"\n"]}),"\n",(0,s.jsx)(a.p,{children:"The following are examples of how to use these macros in C:"}),"\n",(0,s.jsx)(a.pre,{children:(0,s.jsx)(a.code,{children:"AIL_UUID VarA = M_DEFAULT_UUID;\r\nAIL_UUID VarA = M_DEFAULT_UUID;\n"})}),"\n",(0,s.jsx)(a.pre,{children:(0,s.jsx)(a.code,{children:"if(M_COMPARE_AIL_UUID(VarA, VarB)) \r\n { /* Do something if VarA == VarB; */ }\n"})}),"\n",(0,s.jsx)(a.pre,{children:(0,s.jsx)(a.code,{children:"if(M_IS_DEFAULT_UUID(VarA)) \r\n { /* Do something if VarA == M_DEFAULT_UUID; */ }\n"})}),"\n",(0,s.jsx)(a.pre,{children:(0,s.jsx)(a.code,{children:"if(M_IS_NULL_UUID(VarB)) \r\n { /* Do something if VarB == M_NULL_UUID; */ }\n"})}),"\n",(0,s.jsxs)(a.p,{children:["Note, you can use ",(0,s.jsx)(a.em,{children:"AIL_UUID"})," variables normally in a C++ program, since the ",(0,s.jsx)(a.em,{children:"AIL_UUID"})," data type, in C++, implements the equal (==) and not equal (!=) comparison operators."]})]})}function h(e={}){const{wrapper:a}={...(0,n.R)(),...e.components};return a?(0,s.jsx)(a,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},28453(e,a,t){t.d(a,{R:()=>r,x:()=>o});var i=t(96540);const s={},n=i.createContext(s);function r(e){const a=i.useContext(n);return i.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function o(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),i.createElement(n.Provider,{value:a},e.children)}}}]);